// Tech icons component with SVG logos for various technologies

interface TechIconProps {
  name: string
  className?: string
}

// Added TechIcon component export
export function TechIcon({ name, className = "w-6 h-6" }: TechIconProps) {
  const normalizedName = name.toLowerCase().replace(/[\s.]/g, "")
  const IconComponent = TechIcons[normalizedName]

  if (IconComponent) {
    return (
      <div className={className}>
        <IconComponent />
      </div>
    )
  }

  // Fallback for unknown technologies
  return (
    <div
      className={`${className} flex items-center justify-center bg-muted rounded text-xs font-bold text-muted-foreground`}
    >
      {name.charAt(0).toUpperCase()}
    </div>
  )
}

